{
  "summary": "This paper introduces AmbiBench, a novel benchmark designed to study task ambiguity in language models and humans through six ambiguously-specified binary classification tasks. It evaluates various large language models and humans on their ability to resolve ambiguity using instructions and examples, highlighting the critical role of RLHF and model scale, and proposes a finetuning approach to improve ambiguity resolution without RLHF.",
  "strengths": [
    {
      "point": "Novel benchmark targeting task ambiguity distinct from input ambiguity",
      "evidence": "AmbiBench consists of six controlled binary classification tasks with two salient linguistic features, allowing precise manipulation and measurement of task ambiguity."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple large language models and humans",
      "evidence": "Evaluations include OpenAI models with and without RLHF, AI21 Jurassic-1 Jumbo, T0++, and human participants, demonstrating differences in ambiguity resolution capabilities."
    },
    {
      "point": "Insightful findings on the importance of RLHF and model scale for resolving task ambiguity",
      "evidence": "Only the largest RLHF-trained model approaches or exceeds human performance on instruction-based disambiguation, while smaller or non-RLHF models perform poorly."
    },
    {
      "point": "Proposed finetuning strategy using ambiguous in-context examples to improve standard models",
      "evidence": "Finetuning a standard large language model on ambiguous examples closes the performance gap with RLHF models and generalizes better to unseen ambiguous tasks."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison to prior ambiguity-related work and benchmarks",
      "evidence": "Related Work section lacks thorough positioning of AmbiBench relative to existing ambiguity studies in NLP, such as pragmatic inference or few-shot prompting ambiguity."
    },
    {
      "point": "Methodological limitations due to exclusive focus on binary classification tasks",
      "evidence": "No justification for restricting to binary tasks; absence of discussion or experiments on multi-class or structured prediction tasks limits scope."
    },
    {
      "point": "Potential bias from template-based sentence generation not analyzed",
      "evidence": "No human evaluation of sentence naturalness or analysis of distributional biases introduced by programmatic template generation."
    },
    {
      "point": "Evaluation lacks diverse baselines beyond large pretrained models",
      "evidence": "No inclusion of smaller or alternative architectures like fine-tuned BERT or RoBERTa models to contextualize difficulty or ambiguity effects."
    },
    {
      "point": "Metrics focus solely on accuracy without uncertainty or calibration measures",
      "evidence": "Given the ambiguity focus, absence of uncertainty quantification limits understanding of models' recognition of ambiguity and confidence."
    },
    {
      "point": "Prompt format sensitivity not fully explored",
      "evidence": "Only two prompt styles tested with limited analysis; no systematic study of prompt engineering effects on ambiguity resolution."
    },
    {
      "point": "Reproducibility concerns due to missing finetuning details and code release",
      "evidence": "Critical hyperparameters and hardware details for finetuning are omitted; no mention of releasing AmbiBench code or data generation scripts."
    },
    {
      "point": "Ambiguity definition and operationalization lack formal rigor",
      "evidence": "The distinction between task and input ambiguity is stated but not formally defined or quantified per example."
    },
    {
      "point": "Human evaluation protocol underexplained",
      "evidence": "Limited details on participant instructions, demographics, or quality control measures, raising questions about validity of human baselines."
    },
    {
      "point": "Limited discussion on multilinguality and real-world applicability",
      "evidence": "All experiments conducted in English; no exploration of generalization to other languages or complex real-world ambiguous tasks."
    },
    {
      "point": "Generalisability of finetuning gains and RLHF effects not fully established",
      "evidence": "Finetuning experiments conducted on a single model and task type; no ablation to isolate RLHF's causal role or test cross-domain transfer."
    },
    {
      "point": "No analysis of failure modes or error types",
      "evidence": "Results focus on aggregate accuracy without examining specific error patterns or reasons for ambiguity resolution failures."
    }
  ],
  "questions": [
    {
      "question": "How does AmbiBench compare to existing ambiguity benchmarks or theoretical frameworks in NLP?",
      "motivation": "Understanding its novelty and contribution requires positioning relative to prior work on ambiguity, pragmatic inference, and few-shot prompting."
    },
    {
      "question": "Can the benchmark and findings generalize beyond binary classification and English to more complex, multilingual, or real-world tasks?",
      "motivation": "Broader applicability is crucial for the impact of this work on practical NLP systems facing ambiguity."
    },
    {
      "question": "What is the impact of prompt engineering and alternative prompt formats on ambiguity resolution across different models?",
      "motivation": "Prompt design may be a key factor in mitigating ambiguity, and systematic study could inform better model usage."
    },
    {
      "question": "How do models express uncertainty or confidence when faced with ambiguous tasks, and can uncertainty metrics improve evaluation?",
      "motivation": "Evaluating models' recognition of ambiguity is important for safety, interpretability, and trustworthiness."
    },
    {
      "question": "What are the typical failure modes when models fail to resolve task ambiguity?",
      "motivation": "Error analysis could guide future model improvements and better understanding of ambiguity challenges."
    },
    {
      "question": "Will finetuning on ambiguous examples improve ambiguity resolution in smaller or non-RLHF models and across diverse tasks?",
      "motivation": "Assessing generalizability of the finetuning approach is important for practical adoption."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
